import{_ as e,o as t,c as s,a3 as o}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 蛇","description":"巳蛇——机敏灵活，知错能改","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 蛇","description":"巳蛇——机敏灵活，知错能改"},"headers":[],"relativePath":"changshi/shengxiao/she.md","filePath":"changshi/shengxiao/she.md","lastUpdated":1779783531000}'),i={name:"changshi/shengxiao/she.md"};function n(r,a,h,p,c,l){return t(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="巳蛇" tabindex="-1">巳蛇 <a class="header-anchor" href="#巳蛇" aria-label="Permalink to &quot;巳蛇&quot;">​</a></h1><blockquote><p>地支「巳」· 巳时（09:00–11:00）· 五行属火 · 阴阳为阴</p></blockquote><p>蛇机敏灵活，巳时多隐藏在草丛中。逢巳年出生的人也被称为「属小龙」。上古时代蛇被视为神灵——女娲娘娘、伏羲皆为人身蛇尾的形象。在风水学中，蛇更是被誉为荣华富贵吉祥的动物，老话说「蛇不进福薄的地方」。</p><h2 id="生肖故事-四条腿的代价" tabindex="-1">生肖故事：四条腿的代价 <a class="header-anchor" href="#生肖故事-四条腿的代价" aria-label="Permalink to &quot;生肖故事：四条腿的代价&quot;">​</a></h2><p>很久以前，蛇和青蛙是形影不离的好朋友。那时蛇有四条腿却好吃懒做；青蛙没有腿只能靠肚子蠕动，还经常帮人类除害虫，十分勤快。蛇心生怨恨，开始仇视人类，见人就咬、见畜就吃，弄得人间不得安宁。</p><p>土地神上告天庭，玉帝传唤蛇劝它改恶行善。蛇不仅没有悔过之意还口出狂言。玉帝一怒之下，命令神兵砍掉蛇的四条腿，并将这四条腿赏给备受人类青睐的青蛙。此后蛇失去了四条腿只能爬行，而青蛙有了腿变得更加勤快。</p><p>后来蛇隐匿在草丛中，听到人们对青蛙由衷的赞美，决定洗心革面。它也开始为人类吃害虫，拖着长长的身体一声不响地做好事。一旦恶念萌发，便活活扒掉自己一身皮。蛇死后还把自己的躯体作为药物救治人类。</p><p>玉帝见蛇知错能改，便允许它排入十二生肖。蛇成为生肖后再也不主动伤人了，但它对拥有它四条腿的青蛙耿耿于怀，直到今天蛇还是见了青蛙就咬。</p>',8)])])}const f=e(i,[["render",n]]);export{_ as __pageData,f as default};
